/*
 * RemoveSelectedTimberOwnersBusiness
 * This is the name of the web service that will be called from the server-side.
 * Make sure to replace "RemoveSelectedTimberOwnersBusiness" with your actual web service name.
 *
 * Note: Make sure that your server-side script is configured to call the web service and handle the response.
 *
 * PARAMETERS:
 *              - SelectedItems: Array (Collection of Landowners GUIDs)
 */

const websvcName = "FPANRemoveSelectedTimberOwnersBusiness";

const CallServerSide = function () {
  VV.Form.ShowLoadingPanel();

  const formData = [
    {
      name: "Form ID",
      value: VV.Form.DhDocID,
    },
    {
      name: "Selected Item IDs",
      value: SelectedItems,
    },
  ];

  const data = JSON.stringify(formData);
  const requestObject = $.ajax({
    type: "POST",
    url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
    contentType: `application/json; charset=utf-8`,
    data: data,
  });

  return requestObject;
};

$.when(CallServerSide()).always(function (resp) {
  VV.Form.HideLoadingPanel();

  let messageData = "";

  if (typeof resp.status != "undefined") {
    messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
    displayErrorModal(messageData);
  } else if (typeof resp.statusCode != "undefined") {
    messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;
    displayErrorModal(messageData);
  } else if (resp.meta.status == "200") {
    if (resp.data[0] != "undefined") {
      if (resp.data[0] == "Success") {
        messageData = `Business Timber Owner record(s) removed successfully`;

        VV.Form.RefreshDataGridControl("DG Landowner Businesses");
        VV.Form.RefreshDataGridControl("DG Timber Owner Businesses");
        VV.Form.RefreshDataGridControl("DG Operator Businesses");

        VV.Form.Global.DisplayModal({
          Icon: "success",
          Title: "Success",
          HtmlContent: messageData,
        });
        return;
      } else if (resp.data[0] == "Error") {
        messageData = `An error was encountered. ${resp.data[1]}`;
        displayErrorModal(messageData);
      } else {
        messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
        displayErrorModal(messageData);
      }
    } else {
      messageData = "The status of the response returned as undefined.";
      displayErrorModal(messageData);
    }
  } else {
    messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
    displayErrorModal(messageData);
  }
});

function displayErrorModal(messageData) {
  VV.Form.Global.DisplayModal({
    Title: "Error",
    Icon: "error",
    HtmlContent: messageData,
  });
}

//AddBusiness for FPAN Amendment
//Params - formID, businessName, roles (array of roles)

const websvcName = "LibCreateContactInformationRelation";
let modalContent;

let CallServerSide = function () {
  VV.Form.ShowLoadingPanel();
  // Create the form data to send to the microservice
  const formData = [
    {
      name: "Relation Type",
      value: "Business",
    },
    {
      name: "Related Record ID",
      value: VV.Form.DhDocID,
    },
    {
      name: "Contact Information ID",
      value: formID,
    }
  ];

  // Ensure 'roles' is an array before iterating
  if (Array.isArray(roles)) {
    // Iterate through the roles array and add them to the form data
    roles.forEach(function (roleName) {
      formData.push({
        name: roleName,
        value: "True",
      });
    });
  }

  // Convert form data to JSON and prepare the server-side call
  let data = JSON.stringify(formData);
  let requestObject = $.ajax({
    type: "POST",
    url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
    contentType: `application/json; charset=utf-8`,
    data: data,
  });
  return requestObject;
};
$.when(CallServerSide()).always(function (resp) {
  VV.Form.HideLoadingPanel();
  let messageData = "";
  if (typeof resp.status != "undefined") {
    messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
    displayErrorModal(messageData);
  } else if (typeof resp.statusCode != "undefined") {
    messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;
    displayErrorModal(messageData);
  } else if (resp.meta.status == "200") {
    if (resp.data[0] !== "undefined") {
      if (resp.data[0] === "Success") {

        VV.Form.Global.RefreshFormElements();

        VV.Form.Global.DisplayModal({
          Title: "Business Associated",
          Icon: "success",
          HtmlContent: `<div style="align-items: center; gap: 1rem; width: 100%; font-size: 1.1em;">
                <p>You've successfully associated the business:</p>
                <p style="font-weight: bold;">[${businessName}]</p>
                <p>as a ${roles[0]} to this application.</p>
                </div>`,
          showCancelButton: false,
          allowOutsideClick: false,
          okFunction: function () {
            clearFieldsCallback()
              .then(() => {
                VV.Form.Global.RefreshFormElements();
              })
              .then(() => {
                VV.Form.DoAjaxFormSave();
              })
              .catch((err) => {
                console.error("Error when adding business:", err);
              });
          },
        });
        /*VV.Form.SetFieldValue("Multiple Landowners", true)
          .then(() => {
            VV.Form.RefreshDataGridControl("DG Businesses");
          })
          .then(VV.Form.DoAjaxFormSave());*/

      } else if (resp.data[0] === "Error") {
        messageData = `An error was encountered. ${resp.data[1]}`;
        console.log(messageData);
        displayErrorModal();
      } else {
        messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
        console.log(messageData);
        displayErrorModal();
      }
    } else {
      messageData = "The status of the response returned as undefined.";
      console.log(messageData);
      displayErrorModal();
    }
  } else {
    messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
    console.log(messageData);
    displayErrorModal();
  }
});
// Display error modal
function displayErrorModal() {
  VV.Form.Global.DisplayModal({
    Title: "Unable to Add Business",
    Icon: "warning",
    HtmlContent: `
              <div style="text-align: center; padding: 10px;">
                  <p style="font-size: 1.1em; margin-bottom: 15px; color: #555;">
                      Unable to add business: <strong>[${businessName}]</strong>
                  </p>
                  <p style="font-size: 1em; color: #666; margin-bottom: 15px;">
                      This might be due to one of the following reasons:
                  </p>
                  <ul">
                      <li style="margin-bottom: 8px;">The business may already be associated</li>
                      <li style="margin-bottom: 8px;">Required information might be missing</li>
                  </ul>
                  <p style="font-size: 0.9em; color: #666; margin-top: 15px;">
                      Please verify the information and try again. If the issue persists, 
                      contact support for assistance.
                  </p>
              </div>`,
  });
}

// Callback function to clear the field values
async function clearFieldsCallback() {
  const label = roles[0] + ' Business';
  const promises = [
    VV.Form.SetFieldValue(`${label} Search Business ID Number`, ""),
    VV.Form.SetFieldValue(`${label} Search Business Name`, ""),
    VV.Form.SetFieldValue(`${label} Search Country`, "Select Item"),
    VV.Form.SetFieldValue(`${label} Search Postal Zip Code`, ""),
    VV.Form.SetFieldValue(`${label} Search Address Line 1`, ""),
    VV.Form.SetFieldValue(`${label} Search Addresss Line 2`, ""),
    VV.Form.SetFieldValue(`${label} Search Address Line 3`, ""),
    VV.Form.SetFieldValue(`${label} Search City`, ""),
    VV.Form.SetFieldValue(`${label} Search Province State`, "Select Item"),
    VV.Form.SetFieldValue(`${label} Search County`, "Select Item"),
    VV.Form.SetFieldValue(`${label} Search Phone`, ""),
    VV.Form.SetFieldValue(`${label} Search Email`, ""),
    VV.Form.SetFieldValue(`${roles[0]} Business Or Individual`, "Select Item")
  ];

  return Promise.all(promises);
}

// btnSubmit_onClick.js for Amendment
let allSignaturesSigned = true;
const formID = VV.Form.GetFieldValue('Form ID');
const oldStatus = VV.Form.GetFieldValue('Status');

VV.Form.CustomQuery('zLookup Signature Status By Application', formID).then((res) => {
  res.forEach((signature) => {
    if (signature.status !== 'Signature Completed') {
      allSignaturesSigned = false;
    }
  });
  if (VV.Form.GetFieldValue('FPAN Number') === '') {
    VV.Form.Global.DisplayModal({
      Title: '<b>Warning</b>',
      Icon: 'warning',
      HtmlContent:
        'An <b>FPA/N Number</b> is required in order to continue. Please ensure this field is completed before proceeding.',
    });
  } else if (allSignaturesSigned == false) {
    VV.Form.Global.DisplayModal({
      Title: 'Error',
      Icon: 'error',
      HtmlContent: 'One or more signatures have not been signed',
    });
  } else {
    VV.Form.Global.DisplayModal({
      Title: 'Confirm',
      Icon: 'question',
      HtmlContent: 'Are you sure you would like to submit this application?',
      okFunction: () => {
        VV.Form.SetFieldValue('Status', 'Submitted')
          .then(() => VV.Form.DoAjaxFormSave())
          .then(() => VV.Form.SetFieldValue('Form Submitted', 'True'))
          .then(() => {
            return VV.Form.Global.SubmitApplicationUpdate()
              .then(() => VV.Form.Template.CreateStatusHistory('Submitted', oldStatus))
              .then(() => VV.Form.Template.CreateStatusHistory('Received', 'Submitted'));
          })
          .then(() => {
            return Promise.all([
              VV.Form.SetFieldValue('Amendment Status', 'Received'),
              VV.Form.SetFieldValue('old Amendment Status', 'Received')              
            ]);
          })
          .then(() => VV.Form.DoAjaxFormSave())
          .catch((error) => {
            console.error('Error during form submission:', error);
          });
      },
    });
  }
});

// Template GUID goes here
