// Show a loader / disable UI while we process
//If VV.Form.Global.ShowLoadingPanel is undefined (not present in some form templates), the && short-circuits and prevents a runtime error.
VV.Form.Global.ShowLoadingPanel && VV.Form.Global.ShowLoadingPanel();
const oldStatus = VV.Form.GetFieldValue('Status');

Promise.resolve()
  .then(() => {
    // STEP 1: Apply all in-memory changes BEFORE saving
    // Generate timestamp in Pacific Time (Washington State)
    const nowPT = new Date().toLocaleString('en-US', {
      timeZone: 'America/Los_Angeles',
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: true,
    });

    // Update fields in memory
    VV.Form.SetFieldValue('Notification Flag', true);
    VV.Form.SetFieldValue('Resubmitted At', nowPT);
    VV.Form.SetFieldValue('Status', 'Revisions Received');
  })
  .then(() => VV.Form.Global.SubmitApplicationUpdate())
  // create status history record when status changes -- pass old and new status values
  .then(() => VV.Form.Template.CreateStatusHistory(VV.Form.GetFieldValue('Status'), oldStatus))
  .then(() => {
    // STEP 2: Single persistence point — save AFTER all updates complete
    return VV.Form.DoAjaxFormSave();
  })
  .then(() => {
    // STEP 3: UI sync AFTER persistence so RRCs/DGs/DDs reflect saved data
    if (VV.Form.Global.RefreshFormElements) {
      VV.Form.Global.RefreshFormElements();
    }

    VV.Form.Global.DisplayModal({
      Title: 'Success',
      Icon: 'success',
      HtmlContent: 'Your form has been successfully resubmitted.',
    });
  })
  .catch((error) => {
    // Centralized error messaging
    VV.Form.Global.DisplayModal({
      Title: error?.message || 'Submission Error',
      Icon: 'error',
      HtmlContent: error?.messageDetail || 'We could not resubmit your form. Please try again.',
    });
  })
  .finally(() => {
    // Always restore UI state
    VV.Form.Global.HideLoadingPanel && VV.Form.Global.HideLoadingPanel();
  });

