// ContactSearch for Contact Records on FPAN Amendment form
// Param - role
const websvcName = "LibContactInformationSearch";
let modalContent;

// Define the maximum number of results allowed before prompting the user to refine their search
const recordThreshold = 50;
const isBusinessSigner = VV.Form.GetFieldValue(`${role} Business Or Individual`) === "Business";

//Define the maximum number of results allowed to include the "Add Business" button
const addContactThreshold = 25;
const role1 = 'Surveyor';
const role2 = 'Landowner';

// Determine the correct prefix based on the role
let prefix;

switch (role) {
  case 'Landowner':
    prefix = 'Landowner Search';
    break;
  case 'Timber Owner':
    prefix = 'Timber Owner Search';
    break;
  case 'Operator':
    prefix = 'Operator Search';
    break;
  default:
    throw new Error(`Invalid role: ${role}`);
}

let CallServerSide = function () {
    VV.Form.ShowLoadingPanel();

    // Create the form data to send to the microservice
    const formData = [
        { name: "First Name", value: VV.Form.GetFieldValue(`${prefix} First Name`) },
        { name: "Last Name", value: VV.Form.GetFieldValue(`${prefix} Last Name`) },
        { name: "Country", value: VV.Form.GetFieldValue(`${prefix} Country`) },
        { name: "Zip Code", value: VV.Form.GetFieldValue(`${prefix} Postal Zip Code`) },
        { name: "Address Line 1", value: VV.Form.GetFieldValue(`${prefix} Address Line 1`) },
        { name: "Address Line 2", value: VV.Form.GetFieldValue(`${prefix} Address Line 2`) },
        { name: "Address Line 3", value: VV.Form.GetFieldValue(`${prefix} Address Line 3`) },
        { name: "City", value: VV.Form.GetFieldValue(`${prefix} City`) },
        { name: "State", value: VV.Form.getDropDownListText(`${prefix} Province State`) },
        { name: "County", value: VV.Form.GetFieldValue(`${prefix} County`) },
        { name: "Phone", value: VV.Form.GetFieldValue(`${prefix} Phone`) },
        { name: "Email", value: VV.Form.GetFieldValue(`${prefix} Email`) },
    ];

    // Convert form data to JSON and prepare the server-side call
    let data = JSON.stringify(formData);
    let requestObject = $.ajax({
        type: "POST",
        url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${websvcName}`,
        contentType: `application/json; charset=utf-8`,
        data: data,
    });

    return requestObject;
};

$.when(CallServerSide()).always(function (resp) {
    VV.Form.HideLoadingPanel();
    let messageData = "";

    if (typeof resp.status != "undefined") {
        messageData = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
        displayErrorModal(messageData);
    } else if (typeof resp.statusCode != "undefined") {
        messageData = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server. This may mean that the servers to run the business logic are not available.`;
        displayErrorModal(messageData);
    } else if (resp.meta.status == "200") {
        if (resp.data[0] !== "undefined") {
            if (resp.data[0] === "Success") {
                const searchResults = resp.data[2].results;

                // Check if the number of records exceeds the threshold
                if (searchResults.length >= recordThreshold) {
                    modalContent = `Too many results were returned. Please refine your search criteria to narrow down the results.`;
                    VV.Form.Global.DisplayModal({
                        Icon: "warning",
                        Title: "Refine Search",
                        HtmlContent: modalContent,
                        showCancelButton: false,
                        ConfirmText: "OK",
                    });
                } else if (searchResults.length > 0) {
                    // Format the search results to be displayed in rows, using predefined keys
                    const recordsArray = searchResults.map((record) => ({
                        "first Name": record["first Name"] || "N/A",
                        "last Name": record["last Name"] || "N/A",
                        "contact Information ID": record["contact Information ID"] || "N/A",
                        "address Line 1": record["address Line 1"] || "N/A",
                        city: record["city"] || "N/A",
                        state: record["state"] || "N/A",
                        "zip Code": record["zip Code"] || "N/A",
                        phone: record["phone"] || "N/A",
                    }));

                    // Display the modal with results, passing callback functions
                    VV.Form.Template.AddContactRecordModal(
                        recordsArray,
                        clearFieldsCallback,
                        role,
                        prefix,
                        searchResults.length < addContactThreshold
                    );
                } else {
                    messageData = `No contact records were found for the given search parameters. If you would like to add a new contact, please click the 'Add New Contact' button, or click 'Cancel' to refine your search.`;

                    VV.Form.Global.DisplayModal({
                        Icon: "warning",
                        Title: "No Results Found",
                        HtmlContent: messageData,
                        Width: 600,
                        ConfirmText: "Add New Contact",
                        dismissFunction: clearFieldsCallback,
                        showCancelButton: true,
                        okFunction: function () {
                            console.log("Add New Contact button clicked");
                            // Create a new object with the contact details
                            const contact = {
                                contactFirstName: VV.Form.GetFieldValue(`${prefix} First Name`),
                                contactLastName: VV.Form.GetFieldValue(`${prefix} Last Name`),
                                contactCountry: VV.Form.GetFieldValue(`${prefix} Country`),
                                contactZipCode: VV.Form.GetFieldValue(`${prefix} Postal Zip Code`),
                                contactAddressLine1: VV.Form.GetFieldValue(`${prefix} Address Line 1`),
                                contactAddressLine2: VV.Form.GetFieldValue(`${prefix} Address Line 2`),
                                contactAddressLine3: VV.Form.GetFieldValue(`${prefix} Address Line 3`),
                                contactCity: VV.Form.GetFieldValue(`${prefix} City`),
                                contactProvinceState: VV.Form.GetFieldValue(`${prefix} Province State`),
                                contactCounty: VV.Form.GetFieldValue(`${prefix} County`),
                                contactPhone: VV.Form.GetFieldValue(`${prefix} Phone`),
                                contactEmail: VV.Form.GetFieldValue(`${prefix} Email`),
                                role: role,
                                relationType: isBusinessSigner ? "Business" : "Individual"
                            };

                            VV.Form.Template.AddNewContact(contact);
                        },
                    });
                }
            } else if (resp.data[0] === "Error") {
                messageData = `An error was encountered. ${resp.data[1]}`;
                displayErrorModal(messageData);
            } else {
                messageData = `An unhandled response occurred when calling ${websvcName}. The form will not save at this time. Please try again or communicate this issue to support.`;
                displayErrorModal(messageData);
            }
        } else {
            messageData = "The status of the response returned as undefined.";
            displayErrorModal(messageData);
        }
    } else {
        messageData = `The following unhandled response occurred while attempting to retrieve data from ${websvcName}: ${resp?.data?.error}`;
        displayErrorModal(messageData);
    }
});

