/*
  Function Name: LoadActivityMap
  Customer:      Washington DNR
  Purpose:       The purpose of this function is to check if there is a
                 sub-form "ActivityMapView" for the current permit/application
                 a user is on.

                 If there is that means it contains the saved view
                 of the activity map. Therefore, set the checkbox "ActivityMapViewSubFormCreated"
                 to true so we don't create a duplicate subform. 

                 If the subform doesn't exist call the webservice "ActivityMapCreateViewSubForm"
                 to create the sub-form "ActivityMapView"

  Parameters:    none
  Date of Dev:   08/22/2025
  Last Rev Date: 08/22/2025
  08/22/2025 - Ross Rhone: Inital revision
*/

//Loading activity map needed for btnActivityMap_onClick.js
VV.Form.Global.GIS_onLoad(event);

//Check if there is a saved activity map view that we can use from the sub form
if(VV.Form.GetFieldValue("ActivityMapViewSubFormCreated") === 'False'){

    const webServiceName = 'ActivityMapCreateViewSubForm';
    const formName = 'Activity Map';
    let message; // the message is set below

    const fpanId = VV.Form.GetFieldValue("Related Record ID");

    if (!fpanId) {
        //displayErrorModal('Error', "Amendment Form Is Not Related to a FPAN. Can't load ActivityMap view.");
        return null;
    }

    VV.Form.ShowLoadingPanel();

    // Check if the subform already exists, prevent duplicate creation
    VV.Form.CustomQuery('zClientSideGetActivityMapView', fpanId).then(results => {
      if(results.length !== 0) {
        VV.Form.SetFieldValue("ActivityMapViewSubFormCreated", 'True');
        VV.Form.DoAjaxFormSave();
        VV.Form.HideLoadingPanel();
        return;
    }
  });


    function CallServerSide() {
        // IF THE FORM IS TOO LARGE DON'T USE THE FOLLOWING LINE AND SEND ONLY DE DATA YOU NEED
        let formData = [];//VV.Form.getFormDataCollection(); // Get all the form fields data

 // Uncomment the following to add more data to the formData object.
        const revisionId = {
            name: 'Related Record ID',
            value: fpanId
        };

        formData.push(revisionId);

        const data = JSON.stringify(formData);

        const requestObject = $.ajax({
            type: 'POST',
            url: `${VV.BaseAppUrl}api/v1/${VV.CustomerAlias}/${VV.CustomerDatabaseAlias}/scripts?name=${webServiceName}`,
            contentType: 'application/json; charset=utf-8',
            data: data,
            success: '',
            error: '',
        });
        return requestObject;
    }

    $.when(CallServerSide())
        .always(function (resp) {
            if (typeof resp.status != 'undefined') {
                message = `A status code of ${resp.status} returned from the server. There is a communication problem with the web servers. If this continues, please contact the administrator and communicate to them this message and where it occurred.`;
                displayErrorModal('Error', message);
                VV.Form.HideLoadingPanel();
            } if (typeof resp.statusCode != 'undefined') {
                message = `A status code of ${resp.statusCode} with a message of '${resp.errorMessages[0].message}' returned from the server.  This may mean that the servers to run the business logic are not available.`;
                displayErrorModal('Error', message);
                VV.Form.HideLoadingPanel();
            } else if (resp.meta.status == '200') {
                if (resp.data[0] != undefined) {
                    if (resp.data[0] == 'Success') {
                        //Set checkbox field to true;
                        VV.Form.SetFieldValue("ActivityMapViewSubFormCreated", 'True');
                        VV.Form.DoAjaxFormSave();
                        VV.Form.HideLoadingPanel();
                    } else {
                        message = `An unhandled response occurred when calling ${webServiceName}. The form will not save at this time.  Please try again or communicate this issue to support.`;
                        displayErrorModal('Error', message);
                        VV.Form.HideLoadingPanel();
                    }
                } else {
                    message = 'The status of the response returned as undefined.';
                    displayErrorModal('Error', message);
                    VV.Form.HideLoadingPanel();
                }
            } else {
                if (resp.data && resp.data.error) {
                  message = `An error was returned from the server when calling ${webServiceName}. The error message is: ${resp.data.error} <br>`;
                }
                if (resp.meta && resp.meta.errors) {
                  message = `Errors were returned from the server when calling ${webServiceName}. The error messages are: ${resp.meta.errors[0].message}`;
                }
                displayErrorModal('Error', message);
                VV.Form.HideLoadingPanel();
            }
        });



    function displayErrorModal(title, messageData) {
        VV.Form.Global.DisplayModal({
            Title: title,
            Icon: "error",
            HtmlContent: messageData,
        });
    }
}

