// FormValidation for FPAN Amendment Request

/* FIELD NAME, VALIDATION TYPE, & EVENT

Question 1d
First Name Contact Person   | Blank  | Blur
Last Name Contact Person    | Blank  | Blur
Email Contact Person        | Email  | Blur
Phone Contact Person        | Phone  | Blur

Question 2
Describe the proposed amendment to the approved FPAN   | Blank  | Blur

*/

// Pass in ControlName to validate a single item or nothing to validate everything.
let ErrorReporting = true,
  controlToCheck;

let RunAll = false;
if (ControlName == null) {
  RunAll = true;
}

const isProponent = VV.Form.GetFieldValue("isProponent") === "True";

/*************************************
    BEGIN GENERATED VALIDATION CODE
**************************************/

//Question 1a - At least one landowner (Business or Individual) associated
// If a Business is added, at least one Signer must be associated with that Business
const landownerBusRecords = VV.Form.Global.DatagridFindRows('DG Landowner Businesses');
const landownerIndRecords = VV.Form.Global.DatagridFindRows('DG Landowners');
const landownerSignerRecords = VV.Form.Global.DatagridFindRows('DG Landowners Signers');

currentField = "Landowner Business Or Individual";
currentValue = VV.Form.GetFieldValue(currentField);

if (isProponent && ([currentField, 'Send for Signature'].includes(ControlName) || RunAll)) {
  if (landownerBusRecords.length < 1 && landownerIndRecords.length < 1) {
    VV.Form.SetValidationErrorMessageOnField(currentField, 'At least one Landowner must be associated.');
    ErrorReporting = false;
  } else if(landownerBusRecords.length > 0 && landownerSignerRecords.length < 1) {
    VV.Form.SetValidationErrorMessageOnField(currentField, 'At least one Business Signer must be associated with the Landowner.');
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField(currentField);
  }
} else {
    VV.Form.ClearValidationErrorOnField(currentField);
}

//Question 1b - At least one timber owner (Business or Individual) associated
// If a Business is added, at least one Signer must be associated with that Business
