    VV.Form.SetValidationErrorMessageOnField(currentField, 'At least one Timber Owner must be associated.');
    ErrorReporting = false;
  } else if(timberOwnerBusRecords.length > 0 && timberOwnerSignerRecords.length < 1) {
    VV.Form.SetValidationErrorMessageOnField(currentField, 'At least one Business Signer must be associated with the Timber Owner.');
    ErrorReporting = false;
  } else {
    VV.Form.ClearValidationErrorOnField(currentField);
  }
