const searchCriteria = [
    { field: `${role} Search First Name`, validate: "Blank" },
    { field: `${role} Search Last Name`, validate: "Blank" },
    { field: `${role} Search Country`, validate: "DDSelect", dropdown: true },
    { field: `${role} Search Postal Zip Code`, validate: "Blank" },
    { field: `${role} Search Address Line 1`, validate: "Blank" },
    { field: `${role} Search Address Line 2`, validate: "Blank" },
    { field: `${role} Search Address Line 3`, validate: "Blank" },
    { field: `${role} Search City`, validate: "Blank" },
    {
        field: `${role} Search Province State`,
        validate: "DDSelect",
        dropdown: true,
    },
    { field: `${role} Search County`, validate: "DDSelect", dropdown: true },
    { field: `${role} Search Phone`, validate: "Blank" },
    { field: `${role} Search Email`, validate: "Blank" },
];

return searchCriteria.some(({ field, validate, dropdown }) => {
  const value = dropdown
    ? VV.Form.getDropDownListText(field)
    : VV.Form.GetFieldValue(field);

  return VV.Form.Global.CentralValidation(value, validate);
});

// datagridName is a string that is the name of the datagrid to setup selectable rows for.

// Array that will hold all GUID of selected rows in the datagrid.
var selectedRows = []

// Select all rows in the passed in datagrid that have a class that shows they are selected.
$(`[vvfieldnamewrapper="${datagridName}"] .selected`).each(function () {

  // Find the alternate GUID.
  var strMatch = "CIRID="
  var indexStart = $(this).prop("innerHTML").indexOf("CIRID=")

  if (indexStart !== -1) {
    var guid = $(this).prop("innerHTML").slice(indexStart + strMatch.length, indexStart + strMatch.length + 36)
    // Push GUID into array.
    selectedRows.push(guid)
  }
});

return selectedRows

