          const formID = $(this).data("formid");
          const selectedRecord = recordsArray.find(
            (record) => record["contact Information ID"] === formID
          );

          if (businessOrindividual === "Business") {
            showAssociateBusinessModal(selectedRecord); //Go to "Associate Business" modal
          } else {
            showAddContactModal(selectedRecord); // Go to "Add Contact" modal
          }
        });
    },
  }).then((result) => {
    if (result.isDismissed) {
      // Call clearFieldsCallback when modal is closed or canceled
      clearFieldsCallback();
    }
  });
}

