/*
    Function Name: Form_onLoad - FPAN Amendment Request
    Customer:      Washington DNR
    Purpose:       This function initializes the FPAN Amendment Request form.
                   It registers all DataGrids, ensures that the form instance is persisted
                   on first load, updates the browser URL to reference the saved record,
                   and sets up user roles, FPAN relations, and document paths.

    Parameters:    None

    Date of Dev:   --/--/----
    Last Rev Date: 10/29/2025

    --/--/---- - Previous contributors: Initial revision
    10/29/2025 - Matias Andrade: Added early form persistence and browser URL update logic
                                 to ensure the saved record reloads correctly after refresh.
*/

// Get the current status of the form
try {
  const formStatus = VV.Form.GetFieldValue('Status');
  if (VV.Form.Global.isNullEmptyUndefined(formStatus)) {
    VV.Form.SetFieldValue('Status', 'Draft');
  }
} catch (error) {
  console.error('Error setting initial Status field:', error);
}

// Register DataGrids
try {
  VV.Form.Global.RegisterDatagrids([
    'DG Landowner Businesses',
    'DG Landowners',
    'DG Timber Owners',
    'DG Timber Owner Businesses',
    'DG Operators',
    'DG Operator Businesses',
    'DG Landowners Signers',
    'DG Timber Owners Signers',
    'DG Operators Signers',
  ]);
} catch (error) {
  console.error('Error registering datagrids:', error);
}

// Save old Amendment Status
try {
  const oldAmendmentStatus = VV.Form.GetFieldValue('Amendment Status');
  VV.Form.SetFieldValue('old Amendment Status', oldAmendmentStatus);
} catch (error) {
  console.error('Error setting old Amendment Status field:', error);
}

// Initialize variables for roles and FPAN relations handling
// Get current roles (synchronous call)
let rolesCache = VV.Form.Global.GetCurrentRoles() || [];

const isSaved = VV.Form.GetFieldValue('Form Saved') === 'True';
const fpanNumber = VV.Form.GetFieldValue('FPAN Number');
const needsRelationLoading = VV.Form.GetFieldValue('Relations Loaded In') === 'False' && fpanNumber;

const isSignatory = rolesCache.some((role) => role === 'signatory');

if (isSignatory) {
  VV.Form.Global.SignatoryDisableButtonByFieldName('btn_Upload');
}

VV.Form.ShowLoadingPanel();

// Early persistence and URL update
VV.Form.DoAjaxFormSave()
  .then(() => {
    try {
      VV.Form.Global.UpdateWindowLocationURL();
    } catch (urlErr) {
      console.error('Error updating URL after first save:', urlErr);
    }

    // Main execution with race condition fixes
    try {
      // Set User Roles field
      VV.Form.SetFieldValue('UserRoles', rolesCache);

      // Process everything in a single sequential chain
      return Promise.resolve()
        .then(() => {
          // Process roles and set flags synchronously
          let isProponent = false;

          for (const role of rolesCache) {
            if (role === 'proponent') {
              isProponent = true;
              VV.Form.SetFieldValue('isProponent', 'True', true);
              VV.Form.SetFieldValue('isOfficeStaff', 'False', true);
            }

            if (role === 'office staff') {
              VV.Form.SetFieldValue('isOfficeStaff', 'True', true).then(() => {
                return VV.Form.SetFieldValue('Created By Office Staff', 'True', true);
              });
              VV.Form.SetFieldValue('isProponent', 'False', true);
            }
          }

          // Check if SetIndividual is needed based on specific conditions
          const isProponentField = VV.Form.GetFieldValue('isProponent') === 'True';
          const IndividualIdPresent = VV.Form.GetFieldValue('Individual ID') !== '';
          const UserIdPresent = VV.Form.GetFieldValue('UserID') !== '';

          const needsSetIndividual = isProponentField && !IndividualIdPresent && !UserIdPresent;

          return needsSetIndividual;
        })
        .then((needsSetIndividual) => {
          // Execute SetIndividual if needed and wait for completion
          if (needsSetIndividual) {
            return VV.Form.Template.SetIndividual();
          }
          return Promise.resolve();
        })
        .then(() => {
          // Load FPAN relations if needed
          // Note: LoadInFPANRelations saves the form internally on success
          if (needsRelationLoading) {
            return VV.Form.Global.LoadInFPANRelations();
          } else if (!fpanNumber) {
            return VV.Form.Global.EnterValidFPANNumber();
          }
          return Promise.resolve();
        })
        .then(() => {
          // Set tab control
          VV.Form.SetFieldValue('Tab Control', 'Main', true);
        })
        .then(() => {
          // Update document path
          return VV.Form.Template.UpdateDocumentPath();
        })
        .then(() => {
          // Load activity map as final step before save
          return VV.Form.Template.LoadActivityMap();
        })
        .then(() => {
          // Save form only if relations weren't loaded (since LoadInFPANRelations saves internally)
          if (!needsRelationLoading) {
            return VV.Form.DoAjaxFormSave();
          }
          return Promise.resolve();
        })
        .then(() => {
          VV.Form.HideLoadingPanel();
        })
        .catch((error) => {
          console.error('Error in sequential execution:', error);

          // Even if something fails, still try to set tab control
          try {
            VV.Form.SetFieldValue('Tab Control', 'Main', true);
          } catch (tabError) {
            console.error('Error setting tab control in catch:', tabError);
          }

          try {
            VV.Form.Template.UpdateDocumentPath();
          } catch (docError) {
            console.error('Error setting document upload path in catch:', docError);
          }
          VV.Form.HideLoadingPanel();
        });
    } catch (error) {
      console.error('Error getting current roles:', error);

      // Fallback execution if roles failed entirely
      try {
        VV.Form.SetFieldValue('Tab Control', 'Main', true);
      } catch (tabError) {
        console.error('Error setting tab control:', tabError);
      }

      try {
        VV.Form.Template.UpdateDocumentPath();
      } catch (docError) {
        console.error('Error setting document upload path:', docError);
      }
      VV.Form.HideLoadingPanel();
    }
  })
  .catch((error) => {
    console.error('Error during initial save / URL update:', error);

    VV.Form.HideLoadingPanel();
  });

