const modalContent = `
<p ${pStyles}>Use the search fields to locate a business to add to your application. Fill in the information you know, such as the business name or address, and click 'Search.' If the business you are looking for is not found, you will have the option to add it manually after the search.</p>
`;

// Calling the CentralMessages function with the updated modalObject
VV.Form.Global.CentralMessages("Help", {
  helpTitle: "Operator Business Search",
  helpText: modalContent,
});

const individual = VV.Form.GetFieldValue("Timber Owner Business Or Individual") == 'Individual';
const styles = `style="text-align: justify"`;
let modalContent = ``;

if(individual){
    modalContent = `
    <p style="text-align: justify; margin-bottom: 15px;">
    The business signer is the person who has authority to sign an application on behalf of the business. Use the search fields to find a contact in the system to add a timber owner to your application. You can search by entering information like their name, address, or email, then click 'Search.' 
      The system will show any matching contacts. If the contact you’re looking for is not found, you will be given the option to add a new timber owner as a new contact.
    </p>
    `;
}else{
    modalContent = `
    <div style="margin: 0 auto; width: 85%">
        <p ${styles}><strong>Business Signer:</strong> To select a signer authorized to act on behalf of a business, first ensure the business itself is added to your application. Once the business has been successfully entered, you will be able to search for the specific individual signer and associate them with that business’s profile within the application.</p>

    </div>
    `;
}

// Calling the CentralMessages function with the modalObject
VV.Form.Global.CentralMessages("Help", {
  helpTitle: "Timber Owner Search",
  helpText: modalContent,
  helpTextAlignment: "left",
});

// Constants
const DEFAULT_SELECT_VALUE = 'Select Item';

const MODAL_CONFIG = {
  confirmation: {
    title: 'Update the Amendment Status History',
    icon: 'question',
    content: 'Do you want to change the current Amendment Status?',
    confirmText: 'Yes',
    secondaryText: 'No',
  },
  success: {
    title: 'Success',
    icon: 'success',
    content: 'Amendment Status successfully updated.',
  },
};

// Pure functions
const isValidStatusChange = (oldStatus, newStatus) => {
  return oldStatus !== newStatus && newStatus !== DEFAULT_SELECT_VALUE;
};

// Promise-based operations
const updateAmendmentFields = (newStatus, originalStatus) => {
  return Promise.all([
    VV.Form.SetFieldValue('old Amendment Status', newStatus),
    VV.Form.SetFieldValue('Status', newStatus),
  ])
    .then(() => VV.Form.Template.DoStatusUpdate(newStatus, originalStatus))
    .then(() => VV.Form.SetFieldValue('Amendment Status Updated At', new Date()))
    .then(() => {
      const statusesWithEffectiveDate = ['Approved', 'Withdrawn', 'Disapproved'];

      if (
        newStatus !== originalStatus &&
        statusesWithEffectiveDate.includes(newStatus)
      ) {
        return VV.Form.SetFieldValue('Effective Date', VV.Form.Global.GetCurrentDate());
      }
    })
    .then(() => VV.Form.DoAjaxFormSave())
    .catch((error) => {
      console.error('Error updating amendment fields:', error);
      throw error;
    });
};

const revertAmendmentStatus = (originalStatus) => {
  return VV.Form.SetFieldValue('Amendment Status', originalStatus)
    .then(() => {
      Swal.close();
    })
    .catch((error) => {
      console.error('Error reverting amendment status:', error);
      throw error;
    });
};

// Modal handlers
const handleConfirmStatusChange = (newStatus, originalStatus) => {
  updateAmendmentFields(newStatus, originalStatus)
    .then(() => {
      VV.Form.Global.DisplayModal({
        Title: MODAL_CONFIG.success.title,
        Icon: MODAL_CONFIG.success.icon,
        HtmlContent: MODAL_CONFIG.success.content,
        showCancelButton: false,
      });
    })
    .catch((error) => {
      console.error('Failed to update status:', error);
      VV.Form.Global.DisplayModal({
        Title: 'Error',
        Icon: 'error',
        HtmlContent:
          'An error occurred while updating the status. Please try again or contact support if the issue persists.',
      });
    });
};

const handleCancelStatusChange = (originalStatus) => {
  revertAmendmentStatus(originalStatus).catch((error) => {
    console.error('Failed to revert status:', error);
  });
};

const showStatusChangeConfirmation = (newStatus, originalStatus) => {
  VV.Form.Global.DisplayModal({
    Title: MODAL_CONFIG.confirmation.title,
    Icon: MODAL_CONFIG.confirmation.icon,
    HtmlContent: MODAL_CONFIG.confirmation.content,
    showCancelButton: false,
    ConfirmText: MODAL_CONFIG.confirmation.confirmText,
    SecondaryText: MODAL_CONFIG.confirmation.secondaryText,
    showDenyButtton: true,
    okFunction: () => handleConfirmStatusChange(newStatus, originalStatus),
    secondFunction: () => handleCancelStatusChange(originalStatus),
  });
};

// Main logic
const currentStatus = VV.Form.GetFieldValue('old Amendment Status');

if (isValidStatusChange(currentStatus, event)) {
  showStatusChangeConfirmation(event, currentStatus);
}

const MAX_QUANTITY = 10;
const selectedItems = VV.Form.Template.DatagridFindSelectedRowsCIRID("DG Landowners");
const isBusiness =
  VV.Form.GetFieldValue("Landowner Business Or Individual") === "Business";

const doOkFunction = () =>
  VV.Form.Template.RemoveSelectedContactInformationRelation(selectedItems, "Landowner", "Individual", isBusiness)

if (selectedItems.length > 0 && selectedItems.length <= MAX_QUANTITY) {
  const htmlContent = `<p>Do you want to remove the selected Landowner(s)?</p>`;

  VV.Form.Global.DisplayModal({
    HtmlContent: htmlContent,
    Icon: "question",
    okFunction: doOkFunction,
    Title: "Confirmation",
  });
} else {
  const htmlContent = `<p>Please select at least one Landowner to remove.</p>`;

  VV.Form.Global.DisplayModal({
    HtmlContent: htmlContent,
    Icon: "error",
    Title: "Error",
  });
}

VV.Form.Template.UpdateDocumentPath();

// If FPAN Number is set after loading relations, load the activity map
VV.Form.Template.LoadActivityMap();

const pStyles = `style="text-align: justify; margin-bottom: 15px;"`;
const ulStyles = `style="margin-left: 20px; text-align: justify;"`;

const modalContent = `
<p ${pStyles}>Choose whether the timber owner is a business or an individual:</p>
<ul ${ulStyles}>
    <li ${pStyles}>If you select <strong>Business</strong>, you will be able to search for and add a business to the application. You will also be able to search for and add timber owners associated with that business.</li>
    <li ${pStyles}>If you select <strong>Individual</strong>, you will only see the option to search for and add individual timber owners.</li>
</ul>
`;

// Calling the CentralMessages function with the updated modalObject
VV.Form.Global.CentralMessages("Help", {
  helpTitle: "Timber Owner Business or Individual",
  helpText: modalContent,
});

const landOrBusiness = VV.Form.GetFieldValue("Timber Owner Business Or Individual").toLowerCase();
let roleLabel = 'Timber Owner';

const initiateSearch = () => {
    if (VV.Form.Template.ValidateSearchCriteriaQuestion1b(landOrBusiness)) {
        VV.Form.Template.ContactSearch('Timber Owner');
    } else {
        VV.Form.Global.DisplayModal({
            Icon: "warning",
            Title: `${roleLabel} Search`,
            HtmlContent: `No search criteria were provided. Please enter search criteria to proceed with the ${roleLabel} search.`,
        });
    }
}

if (landOrBusiness === 'business') {
    roleLabel = "Business Signer";

    // Lookup associated businesses
    const relatedRecordID = VV.Form.GetFieldValue('Form ID')
    VV.Form.CustomQuery('zLookup Contact Information Relation Business', 
        relatedRecordID, 
        `[Related Record ID] <> '${Math.random()}'`).then((res) => {
            const isTimberOwner = res.some(item => item['timber Owner'] === 'True');
            if (res.length != 0 && isTimberOwner) {
                initiateSearch()
            } else {
                // If no associated businesses, display warning
                VV.Form.Global.DisplayModal({
                    Title: 'Please Add A Business',
                    Icon: 'warning',
                    HtmlContent: 'A Business must be associated with the application before assigning a Business Signer.'
                })
            }
        })
} else {
    initiateSearch()
}

const pStyles = `style="text-align: justify; margin-bottom: 15px;"`;
const ulStyles = `style="margin-left: 20px; text-align: justify;"`;

const modalContent = `
<p ${pStyles}>Choose whether the landowner is a business or an individual:</p>
<ul ${ulStyles}>
    <li ${pStyles}>If you select <strong>Business</strong>, you will be able to search for and add a business to the application. You will also be able to search for and add landowners associated with that business.</li>
    <li ${pStyles}>If you select <strong>Individual</strong>, you will only see the option to search for and add individual landowners.</li>
</ul>
`;

// Calling the CentralMessages function with the updated modalObject
VV.Form.Global.CentralMessages("Help", {
  helpTitle: "Landowner Business or Individual",
  helpText: modalContent,
});

// Check if the status is one of the email flag statuses and set the Email Flag accordingly
const emailFlagStatuses = ['Accepted - Under Review', 'Accepted Revisions - Under Review', 'Approved', 'Disapproved', 'Withdrawn'];
const emailFlag = emailFlagStatuses.includes(event) ? 'True' : 'False';
VV.Form.SetFieldValue('Email Flag', emailFlag)

let formStatus = VV.Form.GetFieldValue('Status')

let flagConditions = [
    'Accepted - Under Review',
    'Accepted Revisions - Under Review',
    'Approved',
    'Disapproved',
    'Withdrawn'
]

if (flagConditions.includes(formStatus)) {
    VV.Form.SetFieldValue('Notification Flag', 'True').then(() => VV.Form.DoAjaxFormSave())
}
